import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend, BarChart, Bar 
} from 'recharts';
import './App.css';

const API_BASE_URL = 'http://127.0.0.1:5000/api';
const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

function App() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEverything = async () => {
      try {
        // Backend'den tüm verileri tek seferde çekiyoruz
        const res = await axios.get(`${API_BASE_URL}/dashboard/all`);
        setData(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      }
    };
    fetchEverything();
  }, []);

  if (loading) return (
    <div className="loading-screen">
      <div className="spinner"></div>
      <h2>📊 InsightFlow Hazırlanıyor...</h2>
      <p>Veritabanı bağlantısı kuruluyor...</p>
    </div>
  );

  return (
    <div className="App">
      <div className="dashboard-container">

        {/* Modern Başlık */}
        <header className="main-header">
          <div className="brand">
            <h1>InsightFlow <span>KDS</span></h1>
            <p>E-Ticaret Karar Destek Sistemi</p>
          </div>
          <div className="system-status">
            <span className="dot"></span> Sistem Çevrimiçi
          </div>
        </header>

        {/* 1. SATIR: KPI Kartları */}
        <section className="kpi-grid">
          <KpiCard title="Toplam Gelir" value={`₺${data?.kpis?.total_revenue?.toLocaleString('tr-TR')}`} color="#6366f1" icon="💰" />
          <KpiCard title="Sipariş Sayısı" value={data?.kpis?.total_orders?.toLocaleString('tr-TR')} color="#10b981" icon="📦" />
          <KpiCard title="Aktif Müşteri" value={data?.kpis?.unique_customers?.toLocaleString('tr-TR')} color="#f59e0b" icon="👥" />
          <KpiCard title="Ort. Sepet (AOV)" value={`₺${data?.kpis?.aov?.toLocaleString('tr-TR', { minimumFractionDigits: 0 })}`} color="#8b5cf6" icon="📊" />
        </section>

        {/* 2. SATIR: Ana Grafikler */}
        <section className="charts-main-row">
          <div className="glass-card main-chart">
            <h3>Aylık Satış Trendi</h3>
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={data?.trend}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis hide />
                <Tooltip contentStyle={{borderRadius: '15px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.05)'}} />
                <Line 
                  type="monotone" 
                  dataKey="value" 
                  stroke="#6366f1" 
                  strokeWidth={4} 
                  dot={{ r: 4, fill: '#6366f1', strokeWidth: 2, stroke: '#fff' }} 
                  activeDot={{ r: 8 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div className="glass-card side-chart">
            <h3>Kategori Dağılımı</h3>
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie 
                  data={data?.categories} 
                  dataKey="value" 
                  nameKey="name" 
                  cx="50%" cy="50%" 
                  innerRadius={60} 
                  outerRadius={85} 
                  paddingAngle={8}
                >
                  {data?.categories?.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </section>

        {/* 3. SATIR: Detaylı Analiz (Scrollable alan) */}
        <section className="charts-detail-row">
          <div className="glass-card">
            <h3>En Çok Satan 5 Ürün</h3>
            <ResponsiveContainer width="100%" height={350}>
              <BarChart data={data?.top_products} layout="vertical" margin={{left: 20}}>
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} style={{fontSize: '12px', fontWeight: '500'}} width={100} />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Bar dataKey="value" fill="#6366f1" radius={[0, 10, 10, 0]} barSize={18} />
              </BarChart>
            </ResponsiveContainer>
          </div>

          <div className="glass-card table-card">
            <h3>Son 10 Sipariş</h3>
            <div className="table-wrapper">
              <table className="modern-table">
                <thead>
                  <tr>
                    <th>Müşteri</th>
                    <th>Ürün</th>
                    <th className="text-right">Tutar</th>
                  </tr>
                </thead>
                <tbody>
                  {data?.recent?.map((order, i) => (
                    <tr key={i}>
                      <td className="customer-cell">{order.customer}</td>
                      <td className="product-cell">{order.product}</td>
                      <td className="text-right amount-cell">₺{order.amount.toLocaleString('tr-TR')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </section>

        <footer className="dashboard-footer">
          <p>InsightFlow Karar Destek Sistemi v1.0 | Toplam {data?.kpis?.total_orders} İşlem İncelendi</p>
        </footer>
      </div>
    </div>
  );
}

